from flask import Flask, request, jsonify
import requests
from collections import Counter

app = Flask(__name__)

# Mock database to store image labels
label_db = {}

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    
    if image_id not in label_db:
        label_db[image_id] = []
    
    label_db[image_id].append(label)
    
    return jsonify({'status': 'success'}), 200

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    
    for image_id, labels in label_db.items():
        counter = Counter(labels)
        most_common_label = counter.most_common(1)[0][0]
        aggregated_labels[image_id] = most_common_label
    
    return jsonify(aggregated_labels), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    aggregated_data = request.json
    # Placeholder for model training logic
    print("Training model with data:", aggregated_data)
    
    return jsonify({'status': 'model trained'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)